mapper.select:
SELECT A.orgn_id , A.write_year , A.doc_type , A.doc_no , A.doc_seq , A.safety_health_goal , A.detail_goal_method , A.hr_id , (select Z.hr_nm from esg.tb_hr_info Z where Z.hr_id = A.hr_id ) AS hr_nm , (select Z.orgn_nm from esg.tb_orgn_info Z where Z.orgn_id = A.orgn_id ) AS orgn_nm , B.revised_dt , B.enacted_dt , A.required_resource , A.evaluation_method , A.remark , A.use_yn as use_yn_main , action_doc_type , action_doc_no , action_doc_seq , action_doc_detail_seq , A.action_schedule1 , A.action_schedule2 , A.action_schedule3 , A.action_schedule4 , A.action_schedule5 , A.action_schedule6 , A.action_schedule7 , A.action_schedule8 , A.action_schedule9 , A.action_schedule10 , A.action_schedule11 , A.action_schedule12 , B.use_yn FROM esg.tb_safety_health_objectives_detail A LEFT JOIN esg.tb_safety_health_objectives B ON A.doc_type = B.doc_type AND A.write_year = B.write_year AND A.doc_no = B.doc_no WHERE A.write_year = #{writeYear} AND A.doc_type = #{docType} AND A.doc_no = #{docNo} AND A.orgn_id = #{orgnId}
AND A.doc_seq = #{docSeq}
ORDER BY A.doc_seq DESC;

mapper.delete:
update esg.tb_hse_key_performance_result
SET use_yn = 'N'
, updated_at = now()
, updated_by = #{updatedBy}
WHERE doc_no = #{docNo}
AND write_year = #{writeYear}
AND doc_seq = #{docSeq}
AND doc_seq_detail = #{docSeqDetail};

mapper.update:
UPDATE esg.tb_task_manager_detail
SET complete_dt = now()
WHERE user_id = #{userId}
AND comp_id = #{compId} 
AND task_year = #{taskYear}
AND task_month = #{taskMonth}
AND task_day = #{taskDay}
AND task_seq = #{taskSeq}
AND detail_seq = #{detailSeq};
